public static Double rpn_eval(ArrayList<String> tokens) {
    Map<String, BinaryOperator<Double>> op = new HashMap<String, BinaryOperator<Double>>();
    op.put("+", (a, b) -> a + b);
    op.put("-", (a, b) -> a - b);
    op.put("*", (a, b) -> a * b);
    op.put("/", (a, b) -> a / b);
    Stack<Double> stack = new Stack<>();
    for (String token : tokens) {
        if (Double.class.isInstance(token)) {
            stack.push(Double.valueOf(token));
        } else {
            Double b = stack.pop();
            Double a = stack.pop();
            BinaryOperator<Double> bin_op = op.get(token);
            Double c = bin_op.apply(a, b);
            stack.push(c);
        }
    }
    return stack.pop();
}

public static Double rpn_eval(ArrayList<Object> tokens) {
    Map<String, BinaryOperator<Double>> op = new HashMap<String, BinaryOperator<Double>>();
    op.put("+", (a, b) -> a + b);
    op.put("-", (a, b) -> a - b);
    op.put("*", (a, b) -> a * b);
    op.put("/", (a, b) -> a / b);
    Stack<Double> stack = new Stack<>();
    for (Object token : tokens) {
        if (token instanceof Double) {
            stack.push((Double) token);
        } else {
            String operator = (String) token;
            Double b = stack.pop();
            Double a = stack.pop();
            Double c = op.get(operator).apply(a, b);
            stack.push(c);
        }
    }
